# templates/agent-dev/main.tf — Terraform template for agent dev env
variable "env_name" {}
variable "team" {}
variable "model_provider" {}
variable "ttl_days" { default = 7 }

resource "kubernetes_namespace" "agent_dev" {
  metadata {
    name = "agent-dev-${var.env_name}"
    labels = {
      team        = var.team
      ttl-days    = tostring(var.ttl_days)
      cost-center = "engineering"
      env-type    = "development"
    }
  }
}

resource "vault_secret_mount" "llm_keys" {
  namespace = kubernetes_namespace.agent_dev.metadata[0].name
  path      = "llm-keys/${var.env_name}"

  # Mount approved model provider keys with per-env rate limits
  dynamic "provider_key" {
    for_each = var.model_provider == "both" ? ["openai", "anthropic"] : [var.model_provider]
    content {
      name   = provider_key.value
      source = "vault:secret/platform/llm-keys/${provider_key.value}"
      policy = "llm-dev-rate-limited"
    }
  }
}

resource "helm_release" "observability_agent" {
  name      = "otel-agent-${var.env_name}"
  namespace = kubernetes_namespace.agent_dev.metadata[0].name
  chart     = "platform/otel-agent"
  set {
    name  = "env"
    value = var.env_name
  }
}
